            terms.add(0, temp % 10);
            temp /= 10;
            n++;
        }
        int next_term = 0;
        while (next_term < x) {
            next_term = 0;
            for (int i = 0; i < n; i++) next_term += terms.get(terms.size() - 1 - i);
            terms.add(next_term);
            if (next_term == x) {
                System.out.println("Keith Number");
                return;
            }
        }
        System.out.println("Not Keith Number");
    }
}

